import pandas as pd
import numpy as np

def test():
    data = {"a": ['1', '3', '4', '5', '6'], "b": ['is', 'am', 'island', 'icream', "banana"]}
    df = pd.DataFrame.from_dict(data)

    return not df['a'].str.contains("is").any()
```

